qry:select.qry:xquery:
for $r in sql(' SELECT sum (LIQ25_VAL_VAREN.n_valor) as total_valor FROM LIQ25_PERSONAL_LIQ as V1, LIQ25_VAL_VAREN, PER02_PERSONAL_EMP as PE1, PER01_PERSONAL AS P1, LIQ09_VARIABLES AS LV1, LIQ19_LIQUIDACION AS LIQ1 JOIN V1.oi_personal_liq INNER LIQ25_VAL_VAREN.oi_personal_liq, PE1.oi_personal_emp INNER V1.oi_personal_emp, PE1.oi_personal INNER P1.oi_personal, LV1.oi_variable INNER LIQ25_VAL_VAREN.oi_variable , V1.oi_liquidacion INNER LIQ1.oi_liquidacion WHERE V1.oi_liquidacion = {#PARAMIN:@oi_liquidacion} AND LIQ25_VAL_VAREN.oi_variable = {#SOURCE:@oi_variable} {%? (#PARAMIN:@l_simulacion!='') {% AND LIQ1.l_simulacion = {%= #PARAMIN:@l_simulacion %} %} {% %} %}
