SELECT sum (LIQ25_VAL_VARPN.n_valor) as total_valor FROM LIQ25_PERSONAL_LIQ AS V10, LIQ25_VAL_VARPN, PER02_PERSONAL_EMP AS PE10, PER01_PERSONAL AS P10, LIQ09_VARIABLES AS LV10, LIQ19_LIQUIDACION AS LIQ10 JOIN V10.oi_personal_liq INNER LIQ25_VAL_VARPN.oi_personal_liq, PE10.oi_personal_emp INNER V10.oi_personal_emp, PE10.oi_personal INNER P10.oi_personal, LV10.oi_variable INNER LIQ25_VAL_VARPN.oi_variable , V10.oi_liquidacion INNER LIQ10.oi_liquidacion WHERE V10.oi_liquidacion = {#PARAMIN:@oi_liquidacion} AND LIQ25_VAL_VARPN.oi_variable = {#SOURCE:@oi_variable} {%? (#PARAMIN:@l_simulacion!='') {% AND LIQ10.l_simulacion = {%= #PARAMIN:@l_simulacion %} %} {% %} %}
')/ROWS/ROW
